SELECT d.doctor_id, d.first_name, d.last_name
FROM doctors d
WHERE d.specialty = 'Cardiology';

SELECT a.appointment_id, a.status
FROM appointments a
WHERE a.status = 'completed';

SELECT prescriptions.medication_name
FROM prescriptions
JOIN appointments ON appointments.appointment_id = prescriptions.appointment_id;

SELECT a.appointment_id, a.appointment_date, a.patient_id, a.doctor_id, a.department_id, a.reason, a.diagnosis
FROM appointments a
WHERE a.status = 'completed';

SELECT pr.medication_name, COUNT(*) AS total_prescriptions
FROM prescriptions pr
GROUP BY pr.medication_name;
